import { cards } from "@/utils/card";
export default {
  name: "app-board",
  data() {
    return {
      cards
    };
  },
  methods: {
    btnClick(e) {
      const msg = {
        name: e.name,
        value: e.value
      };
      this.$emit("click", msg);
    }
  }
};
